// --- react-native-svg ---------------------------------------------------------
// Components using SVG primitives (ASBottomTabNavigator shape rendering, icon
// libs) need every primitive resolvable. Returns a passthrough View for any
// requested export so `import Svg, { Path, Defs, ... } from 'react-native-svg'`
// always resolves to a renderable component.
jest.mock('react-native-svg', () => {
  const React = require('react');
  const RN = require('react-native');
  const passthrough = (name) => {
    const C = ({ children, ...props }) =>
      React.createElement(RN.View, props, children);
    C.displayName = name;
    return C;
  };
  const handler = {
    get: (_t, prop) => {
      if (prop === '__esModule') return true;
      if (prop === 'default') return passthrough('Svg');
      if (typeof prop === 'symbol') return undefined;
      return passthrough(String(prop));
    },
  };
  return new Proxy({}, handler);
});

